import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Streaming-Unterbrechung: 0-Token-Fehlerbehebung | Antigravity-Manager","description":"Erfahren Sie, wie Sie Streaming-Unterbrechungen, 0-Token-Fehler und Signaturverfall bei Antigravity Tools beheben können. Bestätigen Sie /v1/messages oder Gemini-Streaming-Aufrufe, verstehen Sie Peek-Vorlesen und Backoff-Wiederholung, und identifizieren Sie schnell die Ursache mit Proxy Monitor und Protokollen, um zu entscheiden, ob eine Kontorotation erforderlich ist.","frontmatter":{"title":"Streaming-Unterbrechung: 0-Token-Fehlerbehebung | Antigravity-Manager","sidebarTitle":"Selbstheilung oder manuelle Intervention","subtitle":"Streaming-Unterbrechung/0 Token/Signaturverfall: Selbstheilungsmechanismus und Fehlersuchpfad","description":"Erfahren Sie, wie Sie Streaming-Unterbrechungen, 0-Token-Fehler und Signaturverfall bei Antigravity Tools beheben können. Bestätigen Sie /v1/messages oder Gemini-Streaming-Aufrufe, verstehen Sie Peek-Vorlesen und Backoff-Wiederholung, und identifizieren Sie schnell die Ursache mit Proxy Monitor und Protokollen, um zu entscheiden, ob eine Kontorotation erforderlich ist.","tags":["faq","streaming","troubleshooting","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"de/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function s(o,e,d,l,h,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="streaming-unterbrechung-0-token-signaturverfall-selbstheilungsmechanismus-und-fehlersuchpfad" tabindex="-1">Streaming-Unterbrechung/0 Token/Signaturverfall: Selbstheilungsmechanismus und Fehlersuchpfad <a class="header-anchor" href="#streaming-unterbrechung-0-token-signaturverfall-selbstheilungsmechanismus-und-fehlersuchpfad" aria-label="Permalink to &quot;Streaming-Unterbrechung/0 Token/Signaturverfall: Selbstheilungsmechanismus und Fehlersuchpfad&quot;">​</a></h1><p>Wenn Sie bei Antigravity Tools Aufrufe an <code>/v1/messages</code> (Anthropic-kompatibel) oder die nativen Gemini-Streaming-Schnittstellen tätigen und auf Probleme wie „Streaming-Ausgabe unterbrochen“, „200 OK aber 0 Token“ oder „Invalid <code>signature</code>“ stoßen, bietet dieser Kurs einen klaren Fehlersuchpfad von der UI bis zu den Protokollen.</p><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Wissen, dass 0-Token-/Unterbrechungsprobleme vom Proxy meistens zunächst durch „Peek-Vorlesen“ abgefangen werden</li><li>Konto und zugeordnetes Modell für die aktuelle Anfrage aus dem Proxy Monitor bestätigen können (<code>X-Account-Email</code> / <code>X-Mapped-Model</code>)</li><li>Anhand der Protokolle beurteilen können, ob es sich um „vorzeitiges Abbrechen des Upstream-Streams“, „Backoff-Wiederholung“, „Kontorotation“ oder „Signaturreparatur-Wiederholung“ handelt</li><li>Wissen, welche Situationen Sie warten sollten, bis der Proxy sich selbst heilt, und wann Sie manuell eingreifen müssen</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>Sie sehen vielleicht diese „Symptome“, wissen aber nicht, wo Sie anfangen sollen:</p><ul><li>Die Streaming-Ausgabe bricht mittendrin ab, und der Client wirkt wie „eingefroren“ und macht nicht mehr weiter</li><li>200 OK, aber <code>usage.output_tokens=0</code> oder der Inhalt ist leer</li><li>In 400-Fehlern erscheint <code>Invalid \\</code>signature`<code>, </code>Corrupted thought signature<code>, </code>must be `thinking`` usw.</li></ul><p>Diese Probleme sind meistens keine „Fehler in Ihrer Anfrage“, sondern resultieren aus Streaming-Übertragung, Upstream-Ratenbegrenzung/-schwankungen oder Signaturblöcken in Historiennachrichten, die die Upstream-Validierung auslösen. Antigravity Tools hat im Proxy mehrere Verteidigungslinien eingerichtet – Sie müssen nur einem festen Pfad folgen, um zu prüfen, wo genau es hakt.</p><h2 id="was-ist-0-token" tabindex="-1">Was ist 0 Token? <a class="header-anchor" href="#was-ist-0-token" aria-label="Permalink to &quot;Was ist 0 Token?&quot;">​</a></h2><p><strong>0 Token</strong> bezeichnet meistens eine Anfrage, die am Ende <code>output_tokens=0</code> zurückgibt und so aussieht, als ob „kein Inhalt generiert wurde“. In Antigravity Tools ist die häufigere Ursache, dass „die Streaming-Antwort endet oder einen Fehler auslöst, bevor sie tatsächlich ausgibt“, nicht dass das Modell wirklich 0 Token generiert hat. Der Proxy versucht, solche leeren Antworten mit Peek-Vorlesen abzufangen und eine Wiederholung auszulösen.</p><h2 id="drei-dinge-die-der-proxy-im-hintergrund-tut-erst-ein-mentales-modell-aufbauen" tabindex="-1">Drei Dinge, die der Proxy im Hintergrund tut (erst ein mentales Modell aufbauen) <a class="header-anchor" href="#drei-dinge-die-der-proxy-im-hintergrund-tut-erst-ein-mentales-modell-aufbauen" aria-label="Permalink to &quot;Drei Dinge, die der Proxy im Hintergrund tut (erst ein mentales Modell aufbauen)&quot;">​</a></h2><h3 id="_1-nicht-streaming-anfragen-konnen-automatisch-in-streaming-anfragen-umgewandelt-werden" tabindex="-1">1) Nicht-streaming-Anfragen können automatisch in Streaming-Anfragen umgewandelt werden <a class="header-anchor" href="#_1-nicht-streaming-anfragen-konnen-automatisch-in-streaming-anfragen-umgewandelt-werden" aria-label="Permalink to &quot;1) Nicht-streaming-Anfragen können automatisch in Streaming-Anfragen umgewandelt werden&quot;">​</a></h3><p>Im Pfad <code>/v1/messages</code> wandelt der Proxy intern eine „nicht-streaming Client-Anfrage“ in eine Streaming-Anfrage um, um den Upstream aufzurufen, sammelt dann nach Empfang des SSE in JSON und gibt es zurück (der Grund dafür wird in den Protokollen als „better quota“ angegeben).</p><p>Quellcodebeleg: <code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>.</p><h3 id="_2-peek-vorlesen-erst-auf-„ersten-gultigen-datenblock-warten-dann-den-stream-an-den-client-ubergeben" tabindex="-1">2) Peek-Vorlesen: Erst auf „ersten gültigen Datenblock“ warten, dann den Stream an den Client übergeben <a class="header-anchor" href="#_2-peek-vorlesen-erst-auf-„ersten-gultigen-datenblock-warten-dann-den-stream-an-den-client-ubergeben" aria-label="Permalink to &quot;2) Peek-Vorlesen: Erst auf „ersten gültigen Datenblock“ warten, dann den Stream an den Client übergeben&quot;">​</a></h3><p>Bei der SSE-Ausgabe von <code>/v1/messages</code> führt der Proxy zunächst ein <code>timeout + next()</code> Vorlesen durch, überspringt Herzschlag-/Kommentarzeilen (beginnend mit <code>:</code>), bis der erste „nicht leere, kein Herzschlag“ Datenblock empfangen wird, bevor mit der eigentlichen Weiterleitung begonnen wird. Wenn die Peek-Phase einen Fehler/Timeout/Stream-Ende auslöst, wird direkt in den nächsten Versuch eingetreten (der nächste Versuch löst meistens eine Kontorotation aus).</p><p>Quellcodebeleg: <code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code>; Das native Gemini-Streaming hat ein ähnliches Peek: <code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>.</p><h3 id="_3-einheitliche-backoff-wiederholung-entscheidung-nach-statuscode-„ob-konten-rotiert-werden-sollen" tabindex="-1">3) Einheitliche Backoff-Wiederholung + Entscheidung nach Statuscode „ob Konten rotiert werden sollen“ <a class="header-anchor" href="#_3-einheitliche-backoff-wiederholung-entscheidung-nach-statuscode-„ob-konten-rotiert-werden-sollen" aria-label="Permalink to &quot;3) Einheitliche Backoff-Wiederholung + Entscheidung nach Statuscode „ob Konten rotiert werden sollen“&quot;">​</a></h3><p>Der Proxy hat für häufige Statuscodes eine klare Backoff-Strategie und definiert, welche Statuscodes eine Kontorotation auslösen.</p><p>Quellcodebeleg: <code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>.</p><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><ul><li>Sie können den Proxy Monitor öffnen (siehe <a href="./../../advanced/monitoring/">Proxy Monitor: Anfrageprotokolle, Filterung, Detailrekonstruktion und Export</a>)</li><li>Sie wissen, dass die Protokolle im Datenverzeichnis unter <code>logs/</code> liegen (siehe <a href="./../../start/first-run-data/">Wichtig für den ersten Start: Datenverzeichnis, Protokolle, Taskleiste und Autostart</a>)</li></ul><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-bestatigen-sie-welchen-schnittstellenpfad-sie-aufrufen" tabindex="-1">Schritt 1: Bestätigen Sie, welchen Schnittstellenpfad Sie aufrufen <a class="header-anchor" href="#schritt-1-bestatigen-sie-welchen-schnittstellenpfad-sie-aufrufen" aria-label="Permalink to &quot;Schritt 1: Bestätigen Sie, welchen Schnittstellenpfad Sie aufrufen&quot;">​</a></h3><p><strong>Warum</strong> Die Selbstheilungsdetails von <code>/v1/messages</code> (claude handler) und nativen Gemini (gemini handler) sind unterschiedlich. Bestätigen Sie zuerst den Pfad, um Zeit auf falschen Protokoll-Schlüsselwörtern zu vermeiden.</p><p>Öffnen Sie den Proxy Monitor, finden Sie die fehlgeschlagene Anfrage und notieren Sie zuerst den Pfad:</p><ul><li><code>/v1/messages</code>: Schauen Sie die Logik in <code>src-tauri/src/proxy/handlers/claude.rs</code> an</li><li><code>/v1beta/models/...:streamGenerateContent</code>: Schauen Sie die Logik in <code>src-tauri/src/proxy/handlers/gemini.rs</code> an</li></ul><p><strong>Was Sie sehen sollten</strong>: In den Anfragedatensätzen können Sie URL/Methode/Statuscode (sowie Anfragezeit) sehen.</p><h3 id="schritt-2-erfassen-sie-aus-dem-antwortheader-„konto-zugeordnetes-modell" tabindex="-1">Schritt 2: Erfassen Sie aus dem Antwortheader „Konto + zugeordnetes Modell“ <a class="header-anchor" href="#schritt-2-erfassen-sie-aus-dem-antwortheader-„konto-zugeordnetes-modell" aria-label="Permalink to &quot;Schritt 2: Erfassen Sie aus dem Antwortheader „Konto + zugeordnetes Modell“&quot;">​</a></h3><p><strong>Warum</strong> Ob die gleiche Anfrage fehlschlägt oder erfolgreich ist, hängt oft davon ab, „welches Konto diesmal ausgewählt wurde“ und „zu welchem Upstream-Modell geroutet wurde“. Der Proxy schreibt diese beiden Informationen in die Antwortheader – notieren Sie sie zuerst, damit Sie die Protokolle später zuordnen können.</p><p>Suchen Sie in der fehlgeschlagenen Anfrage nach diesen Antwortheadern:</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>Diese beiden Werte werden sowohl im <code>/v1/messages</code> als auch im Gemini handler gesetzt (z.B. in der SSE-Antwort von <code>/v1/messages</code>: <code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code>; Gemini SSE: <code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>).</p><p><strong>Was Sie sehen sollten</strong>: <code>X-Account-Email</code> ist die E-Mail-Adresse, <code>X-Mapped-Model</code> ist der tatsächlich angefragte Modellname.</p><h3 id="schritt-3-beurteilen-sie-in-app-log-ob-es-bereits-„in-der-peek-phase-fehlgeschlagen-ist" tabindex="-1">Schritt 3: Beurteilen Sie in app.log, ob es bereits „in der Peek-Phase fehlgeschlagen“ ist <a class="header-anchor" href="#schritt-3-beurteilen-sie-in-app-log-ob-es-bereits-„in-der-peek-phase-fehlgeschlagen-ist" aria-label="Permalink to &quot;Schritt 3: Beurteilen Sie in app.log, ob es bereits „in der Peek-Phase fehlgeschlagen“ ist&quot;">​</a></h3><p><strong>Warum</strong> Ein Peek-Fehler bedeutet meistens, dass „der Upstream überhaupt nicht begonnen hat, gültige Daten auszugeben“. Für solche Probleme ist die häufigste Behandlungsmethode Wiederholung/Kontorotation – Sie müssen bestätigen, ob der Proxy dies ausgelöst hat.</p><p>Lokalisieren Sie zuerst die Protokolldatei (das Protokollverzeichnis stammt aus <code>logs/</code> im Datenverzeichnis und schreibt täglich rollend in <code>app.log*</code>).</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-g-6yw" id="tab-xLpv4SQ" checked><label data-title="macOS/Linux" for="tab-xLpv4SQ">macOS/Linux</label><input type="radio" name="group-g-6yw" id="tab-Zbofe0s"><label data-title="Windows" for="tab-Zbofe0s">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>Suchen Sie dann im neuesten <code>app.log*</code> nach diesen Schlüsselwörtern:</p><ul><li><code>/v1/messages</code> (claude handler): <code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>)</li><li>Nativer Gemini-Streaming: <code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code> (<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>)</li></ul><p><strong>Was Sie sehen sollten</strong>: Wenn eine Peek-Wiederholung ausgelöst wurde, erscheint im Protokoll eine Warnung wie „retrying...“, und anschließend wird der nächste Versuch eingeleitet (der meistens eine Kontorotation mit sich bringt).</p><h3 id="schritt-4-bei-400-invalid-signature-bestatigen-ob-der-proxy-eine-„signaturreparatur-wiederholung-durchgefuhrt-hat" tabindex="-1">Schritt 4: Bei 400/Invalid <code>signature</code> bestätigen, ob der Proxy eine „Signaturreparatur-Wiederholung“ durchgeführt hat <a class="header-anchor" href="#schritt-4-bei-400-invalid-signature-bestatigen-ob-der-proxy-eine-„signaturreparatur-wiederholung-durchgefuhrt-hat" aria-label="Permalink to &quot;Schritt 4: Bei 400/Invalid `signature` bestätigen, ob der Proxy eine „Signaturreparatur-Wiederholung“ durchgeführt hat&quot;">​</a></h3><p><strong>Warum</strong> Signaturfehler stammen oft aus Thinking-Blöcken/Signaturblöcken in Historiennachrichten, die nicht den Upstream-Anforderungen entsprechen. Antigravity Tools versucht, „Historische Thinking-Blöcke herunterstufen + Reparatur-Prompt injizieren“ und erneut zu versuchen – Sie sollten es zuerst selbstheilen lassen.</p><p>Sie können an zwei Signalen erkennen, ob es in die Reparaturlogik eingetreten ist:</p><ol><li>Im Protokoll erscheint <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>)</li><li>Anschließend werden historische <code>Thinking</code>-Blöcke in <code>Text</code> umgewandelt, und am Ende der letzten user-Nachricht wird ein Reparatur-Prompt angehängt (<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code>; Der Gemini handler hängt auch denselben Prompt an <code>contents[].parts</code> an: <code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>)</li></ol><p><strong>Was Sie sehen sollten</strong>: Der Proxy führt nach kurzer Verzögerung automatisch eine Wiederholung durch (<code>FixedDelay</code>) und kann in den nächsten Versuch eintreten.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>[ ] Sie können im Proxy Monitor den Anfragepfad bestätigen (<code>/v1/messages</code> oder natives Gemini)</li><li>[ ] Sie können <code>X-Account-Email</code> und <code>X-Mapped-Model</code> der aktuellen Anfrage abrufen</li><li>[ ] Sie können in <code>logs/app.log*</code> nach Peek-/Wiederholungs-bezogenen Schlüsselwörtern suchen</li><li>[ ] Bei 400-Signaturfehlern können Sie bestätigen, ob der Proxy in die Reparaturlogik „Reparatur-Prompt + Bereinigen von Thinking-Blöcken“ eingetreten ist</li></ul><h2 id="haufige-fehler-vermeiden" tabindex="-1">Häufige Fehler vermeiden <a class="header-anchor" href="#haufige-fehler-vermeiden" aria-label="Permalink to &quot;Häufige Fehler vermeiden&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Was Sie vielleicht tun (❌)</th><th>Empfohlene Vorgehensweise (✓)</th></tr></thead><tbody><tr><td>Bei 0 Token sofort viele manuelle Wiederholungen durchführen</td><td>Immer den Wiederholungsbutton im Client drücken, ohne überhaupt die Protokolle anzusehen</td><td>Erst einmal den Proxy Monitor + app.log prüfen und bestätigen, ob es ein vorzeitiges Abbrechen in der Peek-Phase ist (wird automatisch wiederholt/rotiert)</td></tr><tr><td>Bei <code>Invalid \\</code>signature}` das Datenverzeichnis sofort leeren</td><td><code>.antigravity_tools</code> komplett löschen, Konten/Statistiken sind weg</td><td>Zuerst den Proxy einmal eine „Signaturreparatur-Wiederholung“ ausführen lassen; Nur wenn das Protokoll explizit angibt, dass es nicht wiederherstellbar ist, manuell eingreifen</td></tr><tr><td>„Server-Schwankungen“ als „Konto kaputt“ betrachten</td><td>Bei 400/503/529 immer Konten rotieren</td><td>Ob Rotation wirksam ist, hängt vom Statuscode ab; Der Proxy selbst hat <code>should_rotate_account(...)</code> Regeln (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</td></tr></tbody></table><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>0 Token/Streaming-Unterbrechung werden im Proxy meistens zuerst durch Peek-Vorlesen abgefangen; Ein Peek-Phasenfehler löst eine Wiederholung aus und tritt in den nächsten Versuch ein</li><li><code>/v1/messages</code> kann intern nicht-streaming-Anfragen in Streaming umwandeln und dann wieder zu JSON sammeln, was Ihr Verständnis davon beeinflusst, „warum es wie ein Streaming-Problem aussieht“</li><li>Bei Signaturverfall-400-Fehlern versucht der Proxy, „Reparatur-Prompt + Bereinigen von Thinking-Blöcken“ und erneut zu versuchen – Sie sollten zuerst prüfen, ob dieser Selbstheilungspfad funktioniert</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../appendix/endpoints/">Endpoint-Schnellreferenz</a></strong>.</p></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: Maximale Anzahl Wiederholungsversuche (<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>)</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> Sekunden: Signatur-Cache TTL (<code>src-tauri/src/proxy/signature_cache.rs#L6</code>)</li><li><code>MIN_SIGNATURE_LENGTH = 50</code>: Mindestlänge der Signatur (<code>src-tauri/src/proxy/signature_cache.rs#L7</code>)</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>determine_retry_strategy(...)</code>: Backoff-Strategie nach Statuscode auswählen (<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>)</li><li><code>should_rotate_account(...)</code>: Entscheiden nach Statuscode, ob Konten rotiert werden sollen (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</li><li><code>SignatureCache::cache_session_signature(...)</code>: Sitzungssignatur cachen (<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>)</li></ul></details>',57)])])}const m=n(a,[["render",s]]);export{g as __pageData,m as default};
